class Solution:
    def stoneGameVII(self, stones):
        n = len(stones)
        prefix = [0] * (n + 1)
        for i, v in enumerate(stones):
            prefix[i + 1] = prefix[i] + v
        memo = {}
        def best(i, j):
            if i >= j:
                return 0
            key = (i, j)
            if key in memo:
                return memo[key]
            take_left = (prefix[j + 1] - prefix[i + 1]) - best(i + 1, j)
            take_right = (prefix[j] - prefix[i]) - best(i, j - 1)
            result = max(take_left, take_right)
            memo[key] = result
            return result
        return best(0, n - 1)

